module shift_register(rst, reset, data_out);  

    input  rst;  
    input  reset;  
    output  [2:0] data_out;  
    reg   [2:0] data_out; 
    initial data_out = 0;

    always @(posedge rst)
        begin
            if (reset)
                data_out <= 0;
            else
                data_out <= data_out << 1;
        end  

endmodule
